import React from 'react';
import './App.css';
import { CardList } from './components/card-list/card-list.componenet';
import { Search } from './components/search/search.component';

class App extends React.Component{

  constructor(){
    super();

    this.state = {
      monsters :[],
      searchField : ''
    }; 
  }

  componentDidMount(){
    fetch('https://jsonplaceholder.typicode.com/users')
    .then(response => response.json())
    .then(response => this.setState({ monsters : response}));
  }

  render() {
    const { monsters, searchField } = this.state;
    const filteredMonsters = monsters.filter( monster =>
      monster.name.toLowerCase().includes(searchField.toLowerCase())
    );
    return (
      <div className="App">
          <Search placeholder="Search Monsters" handleChange={ (e) => this.setState({ searchField : e.target.value})} ></Search>
          <CardList monsters={filteredMonsters}></CardList>
      </div>
    );
  }

}


export default App;
